refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
image = imresize(image, [24 32]);
gray = rgb2gray(image);
[labels, centers] = imsegfcm(gray, 4, 3, 2);
segmented = imlabel2rgb(labels);
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(segmented);
